import React, { useEffect, useState } from 'react';
import api from '../api';
import DoctorCard from './DoctorCard'; // Siguroha nga walay { }

const DoctorList = () => {
    const [doctors, setDoctors] = useState([]);

    useEffect(() => {
        api.get('doctors/')
            .then((res: any) => setDoctors(res.data)) // Butangan og : any
            .catch((err: any) => console.error("Error:", err)); // Butangan og : any
    }, []);

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {doctors.map((d: any) => (
                <DoctorCard key={d.doctor_id} doctor={d} />
            ))}
        </div>
    );
};

export default DoctorList;
